class Solution:
    def canPlace(self, prevHeight, currHeight):
        return currHeight > prevHeight
    def maxBlocks(self, heights, n):
        maxBlocks = 0
        prevHeight = heights[0]
        for i in range(1, n):
            if self.canPlace(prevHeight, heights[i]):
                maxBlocks += 1
                prevHeight = heights[i]
        return maxBlocks

